Server Code (server.js)

const WebSocket = require('ws');
const http = require('http');
// ── CONFIGURATION ──
const PORT = 8080;
const WORLD_WIDTH = 2000;
const WORLD_HEIGHT = 2000;
// ── CREATE HTTP SERVER ──
const server = http.createServer((req, res) => {
res.writeHead(200, { 'Content-Type': 'text/html' });
res.end('<h1>Multiplayer Server Running</h1>');
});
// ── CREATE WEBSOCKET SERVER ──
const wss = new WebSocket.Server({ server });
// ── GAME STATE ──
const players = {};
let nextId = 1;
// ── HELPER FUNCTIONS ──
function broadcast(data) {
const message = JSON.stringify(data);
wss.clients.forEach(client => {
if (client.readyState === WebSocket.OPEN) {
client.send(message);
}
});
}
function getPlayerState(id) {
return {
id: id,
x: players[id].x,
y: players[id].y,
color: players[id].color,
name: players[id].name
};
}
function getAllPlayerStates() {
const states = {};
for (let id in players) {
states[id] = getPlayerState(id);
}
return states;
}
// ── WEBHOOKS ──
wss.on('connection', (ws) => {
console.log('New player connected');
// Assign player ID
const playerId = nextId++;
// Assign random color
const colors = ['#ff6b6b', '#5b8cff', '#7fffb2', '#ffbb6b', '#ff6bff', '#6bffb2'];
const color = colors[Math.floor(Math.random() * colors.length)];
// Create player
players[playerId] = {
id: playerId,
x: Math.random() * 400 + 200,
y: Math.random() * 400 + 200,
color: color,
name: `Player ${playerId}`
};
// Send current state to new player
ws.send(JSON.stringify({
type: 'init',
playerId: playerId,
players: getAllPlayerStates()
}));
// Broadcast new player to others
broadcast({
type: 'playerJoined',
player: getPlayerState(playerId)
});
// ── HANDLE INCOMING MESSAGES ──
ws.on('message', (message) => {
try {
const data = JSON.parse(message);
if (data.type === 'move') {
// Update player position
players[playerId].x = data.x;
players[playerId].y = data.y;
// Broadcast update to all clients
broadcast({
type: 'playerMoved',
id: playerId,
x: data.x,
y: data.y
});
}
if (data.type === 'chat') {
broadcast({
type: 'chat',
id: playerId,
name: players[playerId].name,
message: data.message
});
}
if (data.type === 'nameChange') {
players[playerId].name = data.name;
broadcast({
type: 'playerNameChanged',
id: playerId,
name: data.name
});
}
} catch (e) {
console.error('Error processing message:', e);
}
});
// ── HANDLE DISCONNECT ──
ws.on('close', () => {
console.log(`Player ${playerId} disconnected`);
delete players[playerId];
broadcast({
type: 'playerLeft',
id: playerId
});
});
});
// ── START SERVER ──
server.listen(PORT, () => {
console.log(`🚀 Multiplayer server running on ws://localhost:${PORT}`);
console.log(`📊 World size: ${WORLD_WIDTH}x${WORLD_HEIGHT}`);
});

